  struct
    type nonrec t =
      {
      changeId: GUID.t option
        [@ocaml.doc
          "The unique change identifier associated with a specific domain configuration change."];
      startTime: UpdateTimestamp.t option
        [@ocaml.doc
          "The time at which the configuration change is made on the domain."];
      status: OverallChangeStatus.t option
        [@ocaml.doc "The overall status of the domain configuration change."];
      pendingProperties: StringList.t option
        [@ocaml.doc
          "The list of properties in the domain configuration change that are still pending."];
      completedProperties: StringList.t option
        [@ocaml.doc
          "The list of properties in the domain configuration change that have completed."];
      totalNumberOfStages: TotalNumberOfStages.t option
        [@ocaml.doc
          "The total number of stages required for the configuration change."];
      changeProgressStages: ChangeProgressStageList.t option
        [@ocaml.doc
          "The specific stages that the domain is going through to perform the configuration change."];
      lastUpdatedTime: UpdateTimestamp.t option
        [@ocaml.doc
          "The last time that the status of the configuration change was updated."];
      configChangeStatus: ConfigChangeStatus.t option
        [@ocaml.doc "The current status of the configuration change."];
      initiatedBy: InitiatedBy.t option
        [@ocaml.doc
          "The IAM principal who initiated the configuration change."]}
    let make ?changeId =
      fun ?startTime ->
        fun ?status ->
          fun ?pendingProperties ->
            fun ?completedProperties ->
              fun ?totalNumberOfStages ->
                fun ?changeProgressStages ->
                  fun ?lastUpdatedTime ->
                    fun ?configChangeStatus ->
                      fun ?initiatedBy ->
                        fun () ->
                          {
                            changeId;
                            startTime;
                            status;
                            pendingProperties;
                            completedProperties;
                            totalNumberOfStages;
                            changeProgressStages;
                            lastUpdatedTime;
                            configChangeStatus;
                            initiatedBy
                          }
    let to_value x =
      structure_to_value
        [("ChangeId", (Option.map x.changeId ~f:GUID.to_value));
        ("StartTime", (Option.map x.startTime ~f:UpdateTimestamp.to_value));
        ("Status", (Option.map x.status ~f:OverallChangeStatus.to_value));
        ("PendingProperties",
          (Option.map x.pendingProperties ~f:StringList.to_value));
        ("CompletedProperties",
          (Option.map x.completedProperties ~f:StringList.to_value));
        ("TotalNumberOfStages",
          (Option.map x.totalNumberOfStages ~f:TotalNumberOfStages.to_value));
        ("ChangeProgressStages",
          (Option.map x.changeProgressStages
             ~f:ChangeProgressStageList.to_value));
        ("LastUpdatedTime",
          (Option.map x.lastUpdatedTime ~f:UpdateTimestamp.to_value));
        ("ConfigChangeStatus",
          (Option.map x.configChangeStatus ~f:ConfigChangeStatus.to_value));
        ("InitiatedBy", (Option.map x.initiatedBy ~f:InitiatedBy.to_value))]
